def _validate_and_fix_mix_activos(self, series: dict) -> dict:
    """Valida que mix_activos sume ~100% por año y corrige doble conteos."""
    if "mix_activos" not in series:
        return series

    for year, mix in list(series["mix_activos"].items()):
        if not isinstance(mix, dict):
            continue

        total = sum(v for v in mix.values() if isinstance(v, (int, float)))

        # Si suma está fuera del rango aceptable (98-102%), intentar corrección
        if not (98 <= total <= 102):
            console.log(f"[yellow]mix_activos {year} suma {total:.1f}% (esperado ~100%). Aplicando corrección.")

            # Estrategia: si suma > 150%, probablemente hay doble conteo de totales
            # Filtrar claves que contengan "total" o "subtotal" y mantener solo categorías principales
            if total > 150:
                # Mantener solo claves principales (sin "subtotal", "detalle", "desglose")
                cleaned = {k: v for k, v in mix.items() 
                          if not any(x in k.lower() for x in ["subtotal", "detalle", "desglose", "otros_"])}
                new_total = sum(v for v in cleaned.values() if isinstance(v, (int, float)))

                if 98 <= new_total <= 102:
                    series["mix_activos"][year] = cleaned
                    console.log(f"[green]Corregido {year}: {total:.1f}% -> {new_total:.1f}%")
                else:
                    console.log(f"[red]No se pudo corregir automáticamente {year}. Suma: {new_total:.1f}%")

    return series
